import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.CxZWPeXl.js";const p=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"en/dashboard.md","filePath":"en/dashboard.md"}'),i={name:"en/dashboard.md"};function s(n,t,l,d,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><blockquote><p>Keep track of your practice progress and learning outcomes at a glance</p></blockquote><h2 id="page-overview" tabindex="-1">Page Overview <a class="header-anchor" href="#page-overview" aria-label="Permalink to &quot;Page Overview&quot;">​</a></h2><p>The Dashboard is the home page after logging in, providing an overview of your personal learning progress and shortcuts. The page is divided into two areas: <strong>Statistics Cards</strong> and <strong>Recent Practice History</strong>, plus a top navigation bar for system controls.</p><h2 id="top-navigation-system-controls" tabindex="-1">Top Navigation &amp; System Controls <a class="header-anchor" href="#top-navigation-system-controls" aria-label="Permalink to &quot;Top Navigation &amp; System Controls&quot;">​</a></h2><ul><li><strong>Logo/Home:</strong> Returns you to the Dashboard from anywhere.</li><li><strong>Language Switcher:</strong> Toggle the interface language (Supports Traditional Chinese and Vietnamese).</li><li><strong>AI Knowledge Assistant:</strong> Opens a side panel with tools to support agents.</li><li><strong>Admin Panel:</strong> For authorized users to configure platform settings.</li><li><strong>Logout:</strong> Exits the current session.</li></ul><h2 id="statistics-cards" tabindex="-1">Statistics Cards <a class="header-anchor" href="#statistics-cards" aria-label="Permalink to &quot;Statistics Cards&quot;">​</a></h2><h3 id="start-conversation" tabindex="-1">Start Conversation <a class="header-anchor" href="#start-conversation" aria-label="Permalink to &quot;Start Conversation&quot;">​</a></h3><ul><li>A prominent button to enter the practice setup flow and begin a new session.</li></ul><h3 id="cumulative-practice-count" tabindex="-1">Cumulative Practice Count <a class="header-anchor" href="#cumulative-practice-count" aria-label="Permalink to &quot;Cumulative Practice Count&quot;">​</a></h3><ul><li>Total number of practice sessions you have initiated.</li><li>Unit: <strong>Times</strong></li></ul><h3 id="total-conversation-time" tabindex="-1">Total Conversation Time <a class="header-anchor" href="#total-conversation-time" aria-label="Permalink to &quot;Total Conversation Time&quot;">​</a></h3><ul><li>Cumulative duration of all your active practice sessions.</li><li>Unit: <strong>Hours</strong></li></ul><h3 id="consecutive-practice-days" tabindex="-1">Consecutive Practice Days <a class="header-anchor" href="#consecutive-practice-days" aria-label="Permalink to &quot;Consecutive Practice Days&quot;">​</a></h3><ul><li>Number of uninterrupted days you have practiced.</li><li>Unit: <strong>Days</strong> (Resets if a day is missed)</li></ul><h2 id="recent-practice-history" tabindex="-1">Recent Practice History <a class="header-anchor" href="#recent-practice-history" aria-label="Permalink to &quot;Recent Practice History&quot;">​</a></h2><p>Displays your 5 most recent practices in a detailed data table.</p><h3 id="quick-filters" tabindex="-1">Quick Filters <a class="header-anchor" href="#quick-filters" aria-label="Permalink to &quot;Quick Filters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Clock Icon (Default)</td><td>Displays the 5 most recent practice records</td></tr><tr><td>Today</td><td>Filters practice records for today</td></tr><tr><td>Date Picker</td><td>Filter practice records for a specific date (YYYY-MM-DD)</td></tr><tr><td>All</td><td>Jumps to the full &quot;History&quot; page</td></tr></tbody></table><h3 id="data-columns" tabindex="-1">Data Columns <a class="header-anchor" href="#data-columns" aria-label="Permalink to &quot;Data Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Date</td><td>Date the practice was conducted</td></tr><tr><td>Age</td><td>Age of the customer persona</td></tr><tr><td>Gender</td><td>Gender of the customer persona</td></tr><tr><td>Name</td><td>Name of the customer persona (Clickable to view detailed profile)</td></tr><tr><td>Occupation</td><td>Occupation of the customer persona</td></tr><tr><td>Income</td><td>Income level of the customer persona</td></tr><tr><td>Achieved Stage</td><td>The highest sales phase reached (Includes a hover tooltip for details)</td></tr><tr><td>Duration</td><td>Duration of the conversation (Minutes)</td></tr></tbody></table><h3 id="action-buttons" tabindex="-1">Action Buttons <a class="header-anchor" href="#action-buttons" aria-label="Permalink to &quot;Action Buttons&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Description</th></tr></thead><tbody><tr><td>Review (Eye Icon)</td><td>Go to the detailed Evaluation Report page</td></tr><tr><td>Redo (Recycle Icon)</td><td>Start a completely new session using the exact same persona</td></tr><tr><td>Continue (Play Icon)</td><td>Resume an unfinished conversation</td></tr></tbody></table><h3 id="persona-profile-modal" tabindex="-1">Persona Profile Modal <a class="header-anchor" href="#persona-profile-modal" aria-label="Permalink to &quot;Persona Profile Modal&quot;">​</a></h3><p>Clicking on the customer&#39;s <strong>Name</strong> inside the table opens a detailed profile including:</p><ul><li><strong>MBTI Personality Type:</strong> Helps you understand their decision-making style.</li><li><strong>Family &amp; Education Details:</strong> Marital status, education level.</li><li><strong>Relationship:</strong> The relationship context between the agent and the customer.</li><li><strong>&quot;Redo with this role&quot; Button:</strong> Instantly starts a flow with this exact profile.</li></ul><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Start a <a href="./practice.html">Practice Simulation</a></li><li>Understand the <a href="./evaluation.html">Evaluation &amp; Feedback</a></li><li>View the complete <a href="./history.html">History Tracking</a></li></ul>',29)])])}const m=e(i,[["render",s]]);export{p as __pageData,m as default};
